export const Schema = z
    .object({
    世界: z.object({
        当前时间: z.string().prefault(''),
        当前地点: z.string().prefault(''),
        当前区域: z.string().prefault(''),
        种族: z.record(z.string().describe('种族名称'), z.object({
            描述: z.string(),
            特性: z.string(),
            与人族关系: z.string(),
        })).prefault({}),
        势力: z
            .record(z.string().describe('势力名称'), z.object({
            类型: z.enum(['正道', '魔道', '中立', '妖族']),
            描述: z.string(),
            所在区域: z.string(),
            实力等级: z.coerce.number().transform(v => _.clamp(v, 1, 10)),
            与主角关系: z.coerce.number().transform(v => _.clamp(v, -100, 100)),
        }))
            .prefault({}),
        区域: z
            .record(z.string().describe('区域名称'), z.object({
            类型: z.enum(['大陆', '岛屿', '秘境', '海域']),
            描述: z.string(),
            主要势力: z.array(z.string()),
            危险等级: z.coerce.number().transform(v => _.clamp(v, 1, 10)),
            特色资源: z.array(z.string()),
        }))
            .prefault({}),
    }).prefault({}),
    主角: z
        .object({
        名称: z.string().prefault(''),
        性别: z.enum(['男', '女', '其他']).prefault('男'),
        外貌: z.string().prefault(''),
        种族: z.enum(['人族', '妖族', '魔族', '灵族']).prefault('人族'),
        境界: z
            .object({
            当前境界: z
                .enum(['凡人', '练气', '筑基', '金丹', '元婴', '化神', '炼虚', '合体', '大乘', '渡劫'])
                .prefault('凡人'),
            突破进度: z.coerce.number().transform(v => _.clamp(v, 0, 100)).prefault(0),
        })
            .prefault({}),
        灵力: z
            .object({
            当前值: z.coerce.number().transform(v => Math.max(0, v)).prefault(100),
            最大值: z.coerce.number().transform(v => Math.max(100, v)).prefault(100),
            恢复速度: z.coerce.number().transform(v => Math.max(0, v)).prefault(10),
        })
            .prefault({}),
        属性: z
            .object({
            攻击: z.coerce.number().transform(v => _.clamp(v, 1, 999)).prefault(10),
            防御: z.coerce.number().transform(v => _.clamp(v, 1, 999)).prefault(10),
            速度: z.coerce.number().transform(v => _.clamp(v, 1, 999)).prefault(10),
            悟性: z.coerce.number().transform(v => _.clamp(v, 1, 100)).prefault(10),
            体质: z.coerce.number().transform(v => _.clamp(v, 1, 999)).prefault(10),
            神识: z.coerce.number().transform(v => _.clamp(v, 1, 999)).prefault(10),
        })
            .prefault({}),
        功法: z
            .record(z.string().describe('功法名称'), z.object({
            类型: z.enum(['主修', '辅修', '特殊']),
            品阶: z.enum(['凡阶', '灵阶', '玄阶', '地阶', '天阶', '仙阶']),
            描述: z.string(),
            熟练度: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
            效果: z.string(),
        }))
            .prefault({}),
        法术: z
            .record(z.string().describe('法术名称'), z.object({
            类型: z.enum(['攻击', '防御', '辅助', '控制', '特殊']),
            品阶: z.enum(['凡阶', '灵阶', '玄阶', '地阶', '天阶', '仙阶']),
            描述: z.string(),
            灵力消耗: z.coerce.number().transform(v => Math.max(0, v)),
            冷却时间: z.coerce.number().transform(v => Math.max(0, v)),
            效果: z.string(),
        }))
            .prefault({}),
        物品栏: z
            .record(z.string().describe('物品名称'), z.object({
            类型: z.enum(['丹药', '法宝', '材料', '灵石', '功法秘籍', '其他']),
            品阶: z.enum(['凡阶', '灵阶', '玄阶', '地阶', '天阶', '仙阶']),
            描述: z.string(),
            数量: z.coerce.number().transform(v => Math.max(0, v)),
        }))
            .transform(data => _.pickBy(data, ({ 数量 }) => 数量 > 0))
            .prefault({}),
        灵石: z
            .object({
            下品: z.coerce.number().transform(v => Math.max(0, v)).prefault(0),
            中品: z.coerce.number().transform(v => Math.max(0, v)).prefault(0),
            上品: z.coerce.number().transform(v => Math.max(0, v)).prefault(0),
            极品: z.coerce.number().transform(v => Math.max(0, v)).prefault(0),
        })
            .prefault({}),
        声望: z
            .record(z.string().describe('势力名称'), z.coerce.number().transform(v => _.clamp(v, -1000, 1000)))
            .prefault({}),
    })
        .prefault({}),
    NPC: z
        .record(z.string().describe('NPC名称'), z.object({
        基本信息: z.object({
            性别: z.enum(['男', '女', '其他']),
            种族: z.enum(['人族', '妖族', '魔族', '灵族']),
            外貌: z.string(),
            身份: z.string(),
            所属势力: z.string(),
        }),
        境界: z.enum(['凡人', '练气', '筑基', '金丹', '元婴', '化神', '炼虚', '合体', '大乘', '渡劫']),
        关系: z.object({
            好感度: z.coerce.number().transform(v => _.clamp(v, -100, 100)),
            信任度: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
            关系状态: z.enum([
                '陌生人',
                '点头之交',
                '普通朋友',
                '好友',
                '挚友',
                '生死之交',
                '敌对',
                '仇敌',
                '恋人',
                '道侣',
            ]),
            情绪状态: z.enum([
                '平静',
                '友好',
                '高兴',
                '愤怒',
                '悲伤',
                '恐惧',
                '厌恶',
                '警惕',
                '信任',
                '依赖',
            ]),
        }),
        性格: z.string(),
        特点: z.string(),
        备注: z.string(),
    }))
        .prefault({}),
    任务: z
        .object({
        主线任务: z
            .record(z.string().describe('任务名称'), z.object({
            描述: z.string(),
            目标: z.string(),
            进度: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
            奖励: z.string(),
            状态: z.enum(['未开始', '进行中', '已完成', '已失败']),
        }))
            .prefault({}),
        支线任务: z
            .record(z.string().describe('任务名称'), z.object({
            描述: z.string(),
            目标: z.string(),
            进度: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
            奖励: z.string(),
            状态: z.enum(['未开始', '进行中', '已完成', '已失败']),
        }))
            .prefault({}),
        日常任务: z
            .record(z.string().describe('任务名称'), z.object({
            描述: z.string(),
            目标: z.string(),
            进度: z.coerce.number().transform(v => _.clamp(v, 0, 100)),
            奖励: z.string(),
            状态: z.enum(['未开始', '进行中', '已完成', '已失败']),
            冷却: z.string(),
        }))
            .prefault({}),
    })
        .prefault({}),
    设置: z
        .object({
        已完成设置: z.boolean().prefault(false),
        文风: z.enum(['传统修仙', '内省第一人称', '剧情驱动', '轻松日常']).prefault('传统修仙'),
    })
        .prefault({}),
    $flags: z.record(z.string(), z.boolean()).prefault({}),
})
    .prefault({});
