import { defineMvuDataStore } from '@util/mvu';
import { Schema } from '../../schema';

let storeDefinition: ReturnType<typeof defineMvuDataStore> | null = null;

export const useDataStore = () => {
  if (!storeDefinition) {
    const messageId = getCurrentMessageId();
    console.info('Creating store with messageId:', messageId);
    storeDefinition = defineMvuDataStore(Schema as unknown as z.ZodObject, {
      type: 'message',
      message_id: messageId,
    });
  }
  return storeDefinition();
};
