import { defineStore } from 'pinia';
import { ref } from 'vue';

export interface ConfirmOptions {
  title: string;
  message: string;
  confirmText?: string;
  cancelText?: string;
}

export interface PromptOptions {
  title: string;
  message: string;
  placeholder?: string;
  defaultValue?: string;
  confirmText?: string;
  cancelText?: string;
}

export const useDialogStore = defineStore('dialog', () => {
  const showConfirm = ref(false);
  const confirmOptions = ref<ConfirmOptions>({
    title: '确认',
    message: '',
  });
  let confirmResolve: ((value: boolean) => void) | null = null;

  const showPrompt = ref(false);
  const promptOptions = ref<PromptOptions>({
    title: '输入',
    message: '',
  });
  const promptValue = ref('');
  let promptResolve: ((value: string | null) => void) | null = null;

  const confirm = (options: ConfirmOptions): Promise<boolean> => {
    confirmOptions.value = {
      confirmText: '确认',
      cancelText: '取消',
      ...options,
    };
    showConfirm.value = true;
    
    return new Promise((resolve) => {
      confirmResolve = resolve;
    });
  };

  const handleConfirm = (value: boolean) => {
    showConfirm.value = false;
    if (confirmResolve) {
      confirmResolve(value);
      confirmResolve = null;
    }
  };

  const prompt = (options: PromptOptions): Promise<string | null> => {
    promptOptions.value = {
      confirmText: '确认',
      cancelText: '取消',
      ...options,
    };
    promptValue.value = options.defaultValue || '';
    showPrompt.value = true;
    
    return new Promise((resolve) => {
      promptResolve = resolve;
    });
  };

  const handlePromptConfirm = () => {
    showPrompt.value = false;
    if (promptResolve) {
      promptResolve(promptValue.value || null);
      promptResolve = null;
    }
  };

  const handlePromptCancel = () => {
    showPrompt.value = false;
    if (promptResolve) {
      promptResolve(null);
      promptResolve = null;
    }
  };

  return {
    showConfirm,
    confirmOptions,
    showPrompt,
    promptOptions,
    promptValue,
    confirm,
    handleConfirm,
    prompt,
    handlePromptConfirm,
    handlePromptCancel,
  };
});
