import { defineStore } from 'pinia';
import { ref, computed } from 'vue';

export interface Message {
  role: 'user' | 'assistant';
  content: string;
  rawContent?: string;
}

export interface MessageRound {
  id: string;
  userMessage: Message | null;
  assistantMessage: Message | null;
  timestamp: number;
}

export const useMessageStore = defineStore('message', () => {
  const messages = ref<Message[]>([]);
  const rounds = ref<MessageRound[]>([]);
  const currentRoundIndex = ref<number>(-1);
  const showAllRounds = ref(true);

  const visibleMessages = computed(() => {
    if (showAllRounds.value) {
      return messages.value;
    }
    
    if (currentRoundIndex.value < 0 || currentRoundIndex.value >= rounds.value.length) {
      return [];
    }
    
    const round = rounds.value[currentRoundIndex.value];
    const result: Message[] = [];
    
    if (round.userMessage) {
      result.push(round.userMessage);
    }
    if (round.assistantMessage) {
      result.push(round.assistantMessage);
    }
    
    return result;
  });

  const setMessages = (newMessages: Message[]) => {
    messages.value = newMessages;
    rebuildRounds();
  };

  const rebuildRounds = () => {
    rounds.value = [];
    let currentRound: MessageRound | null = null;
    
    for (let i = 0; i < messages.value.length; i++) {
      const msg = messages.value[i];
      
      if (msg.role === 'user') {
        if (currentRound && currentRound.assistantMessage) {
          rounds.value.push(currentRound);
          currentRound = null;
        }
        
        if (!currentRound) {
          currentRound = {
            id: `round_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            userMessage: { ...msg },
            assistantMessage: null,
            timestamp: Date.now(),
          };
        } else {
          currentRound.userMessage = { ...msg };
        }
      } else if (msg.role === 'assistant') {
        if (!currentRound) {
          currentRound = {
            id: `round_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            userMessage: null,
            assistantMessage: { ...msg },
            timestamp: Date.now(),
          };
        } else {
          currentRound.assistantMessage = { ...msg };
        }
        
        if (currentRound.userMessage || currentRound.assistantMessage) {
          rounds.value.push(currentRound);
          currentRound = null;
        }
      }
    }
    
    if (currentRound) {
      rounds.value.push(currentRound);
    }
    
    if (rounds.value.length > 0) {
      currentRoundIndex.value = rounds.value.length - 1;
    }
  };

  const addMessage = (message: Message) => {
    messages.value.push(message);
    
    if (message.role === 'user') {
      const newRound: MessageRound = {
        id: `round_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
        userMessage: { ...message },
        assistantMessage: null,
        timestamp: Date.now(),
      };
      rounds.value.push(newRound);
      currentRoundIndex.value = rounds.value.length - 1;
    } else if (message.role === 'assistant') {
      if (rounds.value.length > 0) {
        const lastRound = rounds.value[rounds.value.length - 1];
        if (!lastRound.assistantMessage) {
          lastRound.assistantMessage = { ...message };
        } else {
          const newRound: MessageRound = {
            id: `round_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
            userMessage: null,
            assistantMessage: { ...message },
            timestamp: Date.now(),
          };
          rounds.value.push(newRound);
        }
      } else {
        const newRound: MessageRound = {
          id: `round_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
          userMessage: null,
          assistantMessage: { ...message },
          timestamp: Date.now(),
        };
        rounds.value.push(newRound);
      }
      currentRoundIndex.value = rounds.value.length - 1;
    }
  };

  const updateMessage = (index: number, message: Message) => {
    if (index >= 0 && index < messages.value.length) {
      messages.value[index] = message;
      
      let roundIndex = 0;
      let msgCount = 0;
      for (let i = 0; i < rounds.value.length; i++) {
        const round = rounds.value[i];
        const roundMsgCount = (round.userMessage ? 1 : 0) + (round.assistantMessage ? 1 : 0);
        
        if (index < msgCount + roundMsgCount) {
          roundIndex = i;
          break;
        }
        msgCount += roundMsgCount;
      }
      
      if (roundIndex < rounds.value.length) {
        const round = rounds.value[roundIndex];
        if (message.role === 'user' && round.userMessage) {
          round.userMessage = { ...message };
        } else if (message.role === 'assistant' && round.assistantMessage) {
          round.assistantMessage = { ...message };
        }
      }
    }
  };

  const clearMessages = () => {
    messages.value = [];
    rounds.value = [];
    currentRoundIndex.value = -1;
  };

  const getMessages = () => {
    return messages.value;
  };

  const setCurrentRound = (index: number) => {
    if (index >= -1 && index < rounds.value.length) {
      currentRoundIndex.value = index;
      showAllRounds.value = false;
    }
  };

  const setShowAllRounds = (show: boolean) => {
    showAllRounds.value = show;
    if (show && rounds.value.length > 0) {
      currentRoundIndex.value = rounds.value.length - 1;
    }
  };

  const getCurrentRound = () => {
    if (currentRoundIndex.value >= 0 && currentRoundIndex.value < rounds.value.length) {
      return rounds.value[currentRoundIndex.value];
    }
    return null;
  };

  return {
    messages,
    rounds,
    currentRoundIndex,
    showAllRounds,
    visibleMessages,
    setMessages,
    addMessage,
    updateMessage,
    clearMessages,
    getMessages,
    setCurrentRound,
    setShowAllRounds,
    getCurrentRound,
    rebuildRounds,
  };
});
