import { defineStore } from 'pinia';
import { ref, computed } from 'vue';

export interface FateNode {
  id: string;
  title: string;
  parentId: string | null;
  roundIndex: number;
  timestamp: number;
  children: string[];
  branchLabel?: string;
}

export const useFateStore = defineStore('fate', () => {
  const nodes = ref<Map<string, FateNode>>(new Map());
  const currentNodeId = ref<string | null>(null);
  const rootNodeId = ref<string | null>(null);

  const currentNode = computed(() => {
    if (!currentNodeId.value) return null;
    return nodes.value.get(currentNodeId.value) || null;
  });

  const getNodePath = (nodeId: string): FateNode[] => {
    const path: FateNode[] = [];
    let currentId: string | null = nodeId;
    
    while (currentId) {
      const node = nodes.value.get(currentId);
      if (node) {
        path.unshift(node);
        currentId = node.parentId;
      } else {
        break;
      }
    }
    
    return path;
  };

  const getChildren = (nodeId: string): FateNode[] => {
    const node = nodes.value.get(nodeId);
    if (!node) return [];
    
    return node.children
      .map(id => nodes.value.get(id))
      .filter((n): n is FateNode => n !== undefined);
  };

  const createNode = (
    roundIndex: number,
    title: string,
    parentId: string | null = null,
    branchLabel?: string
  ): string => {
    const id = `fate_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
    
    const node: FateNode = {
      id,
      title,
      parentId,
      roundIndex,
      timestamp: Date.now(),
      children: [],
      branchLabel,
    };
    
    nodes.value.set(id, node);
    
    if (parentId) {
      const parent = nodes.value.get(parentId);
      if (parent) {
        parent.children.push(id);
      }
    } else {
      rootNodeId.value = id;
    }
    
    currentNodeId.value = id;
    
    return id;
  };

  const createBranch = (
    parentNodeId: string,
    roundIndex: number,
    title: string,
    branchLabel?: string
  ): string => {
    const parent = nodes.value.get(parentNodeId);
    if (!parent) {
      console.warn('Parent node not found:', parentNodeId);
      return '';
    }
    
    return createNode(roundIndex, title, parentNodeId, branchLabel);
  };

  const deleteNode = (nodeId: string) => {
    const node = nodes.value.get(nodeId);
    if (!node) return;

    const deleteRecursive = (id: string) => {
      const n = nodes.value.get(id);
      if (n) {
        n.children.forEach(childId => deleteRecursive(childId));
        nodes.value.delete(id);
      }
    };

    if (node.parentId) {
      const parent = nodes.value.get(node.parentId);
      if (parent) {
        parent.children = parent.children.filter(id => id !== nodeId);
      }
    }

    deleteRecursive(nodeId);

    if (rootNodeId.value === nodeId) {
      rootNodeId.value = null;
      currentNodeId.value = null;
    }

    if (currentNodeId.value === nodeId) {
      currentNodeId.value = node.parentId;
    }
  };

  const setCurrentNode = (nodeId: string) => {
    if (nodes.value.has(nodeId)) {
      currentNodeId.value = nodeId;
    }
  };

  const updateNodeTitle = (nodeId: string, title: string) => {
    const node = nodes.value.get(nodeId);
    if (node) {
      node.title = title;
    }
  };

  const clearAll = () => {
    nodes.value.clear();
    currentNodeId.value = null;
    rootNodeId.value = null;
  };

  const initializeRoot = (title: string = '命途初开'): string | null => {
    if (rootNodeId.value) {
      return rootNodeId.value;
    }
    
    const id = createNode(0, title, null);
    return id;
  };

  const advanceFate = (roundIndex: number, title: string): string => {
    if (!currentNodeId.value) {
      return createNode(roundIndex, title, null);
    }
    
    return createNode(roundIndex, title, currentNodeId.value);
  };

  const getFatePath = (): FateNode[] => {
    if (!currentNodeId.value) return [];
    return getNodePath(currentNodeId.value);
  };

  const exportData = () => {
    return {
      nodes: Array.from(nodes.value.entries()),
      currentNodeId: currentNodeId.value,
      rootNodeId: rootNodeId.value,
    };
  };

  const importData = (data: {
    nodes: [string, FateNode][];
    currentNodeId: string | null;
    rootNodeId: string | null;
  }) => {
    nodes.value = new Map(data.nodes);
    currentNodeId.value = data.currentNodeId;
    rootNodeId.value = data.rootNodeId;
  };

  return {
    nodes,
    currentNodeId,
    rootNodeId,
    currentNode,
    getNodePath,
    getChildren,
    createNode,
    createBranch,
    deleteNode,
    setCurrentNode,
    updateNodeTitle,
    clearAll,
    initializeRoot,
    advanceFate,
    getFatePath,
    exportData,
    importData,
  };
});
